@startuml
title CrossoverOperators's Class Diagram
package "Logic" {
  package "Operators" {
    package "CrossoverOperators" {
      class "CrossoverOperationType" as CrossoverOperationType {
        COMPX
        MEAN
        MPX
        OPC
        TPC
        UC
        crossoverOperator
        text
      }
      class "CrossoverOperator" as CrossoverOperator {
        + generateChild()
        + isCompatible()
        + isSymmetric()
      }
      class "CompositionCrossover" as CompositionCrossover {
        + generateChild()
        + isCompatible()
        + isSymmetric()
      }
      class "MaximalPreservationCrossover" as MaximalPreservationCrossover {
        - rand : Random
        + generateChild()
        + isCompatible()
        + isSymmetric()
        + setSeed()
      }
      class "OnePointCrossover" as OnePointCrossover {
        - RNG : Random
        + generateChild()
        + isCompatible()
        + isSymmetric()
        + setRandomSeed()
      }
      class "UniformCrossover" as UniformCrossover {
        - RNG : Random
        + generateChild()
        + isCompatible()
        + isSymmetric()
        + setRandomSeed()
      }
      class "TwoPointCrossover" as TwoPointCrossover {
        - RNG : Random
        + generateChild()
        + isCompatible()
        + isSymmetric()
        + setRandomSeed()
      }
      class "OrdinalNumberMean" as OrdinalNumberMean {
        + OrdinalNumberMean()
        + generateChild()
        + isCompatible()
        + isSymmetric()
      }
      CrossoverOperationType o-- CrossoverOperator : crossoverOperator
      CrossoverOperator <|-- CompositionCrossover
      CrossoverOperator <|-- MaximalPreservationCrossover
      CrossoverOperator <|-- OnePointCrossover
      CrossoverOperator <|-- UniformCrossover
      CrossoverOperator <|-- TwoPointCrossover
      CrossoverOperator <|-- OrdinalNumberMean
    }
  }
}
@enduml
